public class UrlValidator : IUrlValidator
{
    private readonly IDestinationAllowlist _allowlist;

    public UrlValidator(IDestinationAllowlist allowlist)
    {
        _allowlist = allowlist;
    }

    public async Task<ValidationResult> ValidateUrlAsync(string url)
    {
        if (string.IsNullOrWhiteSpace(url))
        {
            return new ValidationResult
            {
                IsValid = false,
                ErrorMessage = "URL cannot be empty"
            };
        }

        if (!Uri.TryCreate(url, UriKind.Absolute, out Uri uri))
        {
            return new ValidationResult
            {
                IsValid = false,
                ErrorMessage = "Invalid URL format"
            };
        }

        if (uri.Scheme != "https" && uri.Scheme != "http")
        {
            return new ValidationResult
            {
                IsValid = false,
                ErrorMessage = "Only HTTP and HTTPS schemes are allowed"
            };
        }

        if (!_allowlist.IsAllowed(uri.Host))
        {
            return new ValidationResult
            {
                IsValid = false,
                ErrorMessage = $"Host '{uri.Host}' is not in the allowlist"
            };
        }

        if (IsHostnameLocalOrPrivate(uri.Host))
        {
            return new ValidationResult
            {
                IsValid = false,
                ErrorMessage = "Access to local or private hosts is forbidden"
            };
        }

        var ipAddresses = await ResolveHostToIpAddressesAsync(uri.Host);
        
        foreach (var ipAddress in ipAddresses)
        {
            if (IsPrivateOrLocalIpAddress(ipAddress))
            {
                return new ValidationResult
                {
                    IsValid = false,
                    ErrorMessage = $"Host resolves to private/local IP address: {ipAddress}"
                };
            }
        }

        return new ValidationResult
        {
            IsValid = true,
            Uri = uri
        };
    }

    private bool IsHostnameLocalOrPrivate(string host)
    {
        var lowerHost = host.ToLowerInvariant();
        
        if (lowerHost == "localhost" || 
            lowerHost == "127.0.0.1" || 
            lowerHost == "::1" ||
            lowerHost.EndsWith(".local") ||
            lowerHost.EndsWith(".localhost"))
        {
            return true;
        }

        if (Regex.IsMatch(lowerHost, @"^(10\.|172\.(1[6-9]|2[0-9]|3[01])\.|192\.168\.)"))
        {
            return true;
        }

        return false;
    }

    private async Task<List<IPAddress>> ResolveHostToIpAddressesAsync(string host)
    {
        try
        {
            var addresses = await Dns.GetHostAddressesAsync(host);
            return addresses.ToList();
        }
        catch
        {
            return new List<IPAddress>();
        }
    }

    private bool IsPrivateOrLocalIpAddress(IPAddress ipAddress)
    {
        if (IPAddress.IsLoopback(ipAddress))
            return true;

        if (ipAddress.AddressFamily == AddressFamily.InterNetwork)
        {
            byte[] bytes = ipAddress.GetAddressBytes();
            
            if (bytes[0] == 10)
                return true;
            
            if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                return true;
            
            if (bytes[0] == 192 && bytes[1] == 168)
                return true;
            
            if (bytes[0] == 127)
                return true;
            
            if (bytes[0] == 169 && bytes[1] == 254)
                return true;
            
            if (bytes[0] >= 224)
                return true;
        }
        else if (ipAddress.AddressFamily == AddressFamily.InterNetworkV6)
        {
            if (ipAddress.IsIPv6LinkLocal || ipAddress.IsIPv6SiteLocal)
                return true;
            
            byte[] bytes = ipAddress.GetAddressBytes();
            
            if (bytes[0] == 0xfc || bytes[0] == 0xfd)
                return true;
            
            if (bytes[0] == 0xfe && (bytes[1] & 0xc0) == 0x80)
                return true;
        }

        return false;
    }
}

