[Route("api/[controller]")]
public class WebhookProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;
    private readonly IUrlValidator _urlValidator;
    private readonly ILogger<WebhookProxyController> _logger;
    private const int MaxRedirects = 3;

    public WebhookProxyController(
        IHttpClientFactory httpClientFactory,
        IUrlValidator urlValidator,
        ILogger<WebhookProxyController> logger)
    {
        _httpClientFactory = httpClientFactory;
        _urlValidator = urlValidator;
        _logger = logger;
    }

    [HttpPost("forward")]
    public async Task<IActionResult> ForwardWebhook([FromBody] WebhookRequest request)
    {
        if (request == null || string.IsNullOrWhiteSpace(request.TargetUrl))
        {
            return BadRequest(new { error = "Target URL is required" });
        }

        var validationResult = await _urlValidator.ValidateUrlAsync(request.TargetUrl);
        if (!validationResult.IsValid)
        {
            _logger.LogWarning("URL validation failed for {Url}: {Error}", request.TargetUrl, validationResult.ErrorMessage);
            return BadRequest(new { error = validationResult.ErrorMessage });
        }

        try
        {
            var response = await ForwardRequestWithRedirectControlAsync(
                validationResult.Uri,
                request.Method ?? "POST",
                request.Headers,
                request.Body);

            return response;
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Error forwarding webhook to {Url}", request.TargetUrl);
            return StatusCode(500, new { error = "Failed to forward webhook", details = ex.Message });
        }
    }

    private async Task<IActionResult> ForwardRequestWithRedirectControlAsync(
        Uri targetUri,
        string method,
        Dictionary<string, string> headers,
        string body,
        int redirectCount = 0)
    {
        if (redirectCount >= MaxRedirects)
        {
            return BadRequest(new { error = "Maximum redirect limit exceeded" });
        }

        var httpClient = _httpClientFactory.CreateClient("ProxyClient");
        var requestMessage = new HttpRequestMessage(new HttpMethod(method), targetUri);

        if (!string.IsNullOrWhiteSpace(body))
        {
            requestMessage.Content = new StringContent(body, System.Text.Encoding.UTF8, "application/json");
        }

        if (headers != null)
        {
            foreach (var header in headers)
            {
                if (!IsRestrictedHeader(header.Key))
                {
                    requestMessage.Headers.TryAddWithoutValidation(header.Key, header.Value);
                }
            }
        }

        HttpResponseMessage response;
        try
        {
            response = await httpClient.SendAsync(requestMessage);
        }
        catch (HttpRequestException ex)
        {
            _logger.LogError(ex, "HTTP request failed for {Url}", targetUri);
            return StatusCode(502, new { error = "Failed to connect to target URL" });
        }
        catch (TaskCanceledException ex)
        {
            _logger.LogError(ex, "Request timeout for {Url}", targetUri);
            return StatusCode(504, new { error = "Request timeout" });
        }

        if (IsRedirectStatusCode(response.StatusCode))
        {
            var locationHeader = response.Headers.Location;
            if (locationHeader == null)
            {
                return StatusCode((int)response.StatusCode, new { error = "Redirect without Location header" });
            }

            Uri redirectUri;
            if (!locationHeader.IsAbsoluteUri)
            {
                redirectUri = new Uri(targetUri, locationHeader);
            }
            else
            {
                redirectUri = locationHeader;
            }

            var redirectValidation = await _urlValidator.ValidateUrlAsync(redirectUri.ToString());
            if (!redirectValidation.IsValid)
            {
                _logger.LogWarning("Redirect validation failed for {Url}: {Error}", redirectUri, redirectValidation.ErrorMessage);
                return BadRequest(new { error = $"Redirect blocked: {redirectValidation.ErrorMessage}" });
            }

            _logger.LogInformation("Following redirect from {Original} to {Redirect}", targetUri, redirectUri);
            return await ForwardRequestWithRedirectControlAsync(
                redirectUri,
                method,
                headers,
                body,
                redirectCount + 1);
        }

        var responseContent = await response.Content.ReadAsStringAsync();
        var responseHeaders = new Dictionary<string, string>();
        
        foreach (var header in response.Headers)
        {
            responseHeaders[header.Key] = string.Join(", ", header.Value);
        }
        
        foreach (var header in response.Content.Headers)
        {
            responseHeaders[header.Key] = string.Join(", ", header.Value);
        }

        return StatusCode((int)response.StatusCode, new
        {
            statusCode = (int)response.StatusCode,
            headers = responseHeaders,
            body = responseContent
        });
    }

    private bool IsRedirectStatusCode(HttpStatusCode statusCode)
    {
        return statusCode == HttpStatusCode.MovedPermanently ||
               statusCode == HttpStatusCode.Found ||
               statusCode == HttpStatusCode.SeeOther ||
               statusCode == HttpStatusCode.TemporaryRedirect ||
               statusCode == HttpStatusCode.PermanentRedirect;
    }

    private bool IsRestrictedHeader(string headerName)
    {
        var restricted = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Host",
            "Connection",
            "Content-Length",
            "Transfer-Encoding",
            "Upgrade"
        };

        return restricted.Contains(headerName);
    }
